//
//  RouterHelper.swift
//  XiaoPengQiChe
//
//  Created by Kin on 2025/1/14.
//  Copyright © 2025 xiaopeng.com. All rights reserved.
//

import Foundation
import TheRouter
import bBox

/// 新的路由工具，同时兼容新的和旧的路由
/// 目前这部分还不能单独变成模块，因为要依赖XPRouterUtil
///
/// 这里有另一个实现的拦截器逻辑，因为TheRouter的拦截器是白名单模式，与业务预期差距较大
/// 但又不想对TheRouter做太多定制化，影响之后版本同步
@objc(XPRouterHelper) public final class RouterHelper: NSObject {
    @objc public static let shared = RouterHelper()

    @objc public var xpRouterUtilDelegate: RouterUtilDelegate?

    private(set) var interceptors = [RouterHelperInterceptor]()
    private(set) var customisers = [RouterHelperRouterCustomiser]()

    override init() {
        TheRouterManagerBridge.addExcludeLibraryIdentifiers(["com.xiaopeng.XRN",
                                                             "com.unity3d.framework",
                                                             "org.chromium.net.Cronet",
                                                             "com.netease.NIMSDK",
                                                             "-23.TTNetworkManagerFramework",
                                                             "com.aliyun.AIOSDK",
                                                             "com.alibaba.AlivcLibReplayKitExt",
                                                             "com.alibaba.AliyunPlayer.alivcffmpeg"])
        TheRouterManagerBridge.addExcludeClassNames(["HttpDnsService"])
    }

    public final func initServices() {
        TheRouterManager.registerServices(excludeCocoapods: false)
    }

    @objc public final func initRouter() {
        TheRouterManager.loadRouterClass(excludeCocoapods: false,
                                         useCache: BBEnvironment.env == .enterprise || BBEnvironment.env == .production)
        TheRouter.lazyRegisterRouterHandle { url, userInfo in
            return TheRouterManager.addGloableRouter(false, url, userInfo, forceCheckEnable: false)
        }
        TheRouter.globalOpenFailedHandler { info in
            BBLog.info("")
        }
        TheRouter.logcat { url, logType, errorMsg in
            switch logType {
            case .logError:
                BBLog.error("TheRouter \(url) \(errorMsg)")
            case .logNormal:
                BBLog.error("TheRouter \(url) \(errorMsg)")
            }
        }
    }

    public func registerInterceptor(_ interceptor: RouterHelperInterceptor) {
        interceptors.append(interceptor)
        interceptors.sort { $0.priority.rawValue > $1.priority.rawValue }
    }

    public func unregisterInterceptor(_ interceptor: RouterHelperInterceptor) {
        if let index = interceptors.firstIndex(where: { $0 === interceptor }) {
            interceptors.remove(at: index)
        }
    }

    public func addRouterCustomiser(_ customiser: RouterHelperRouterCustomiser) {
        customisers.append(customiser)
        customisers.sort { $0.priority.rawValue > $1.priority.rawValue }
    }

    public func removeRouterCustomiser(_ customiser: RouterHelperRouterCustomiser) {
        if let index = customisers.firstIndex(where: { $0 === customiser }) {
            customisers.remove(at: index)
        }
    }

    @objc public func forceRegisterAllRouters() {
        TheRouterManager.registerRouterMap(false, "", [:])
    }
}

