//  RouterHelperInterceptor.swift
//  XiaoPengQiChe
//
//  Created by Kin on 2025/1/15.
//  Copyright © 2025 xiaopeng.com. All rights reserved.
//

import Foundation

public enum RouterHelperPriority: UInt {
    case low = 0
    case normal = 1
    case high = 2
}

open class RouterHelperInterceptor {
    public let priority: RouterHelperPriority

    public init(priority: RouterHelperPriority) {
        self.priority = priority
    }

    open func shouldIntercept(_ urlString: String, userInfo: [String: Any]) -> Bool {
        return false
    }
}

open class RouterHelperRouterCustomiser {
    public let priority: RouterHelperPriority

    public init(priority: RouterHelperPriority) {
        self.priority = priority
    }

    open func customise(urlString: String, userInfo: [String: Any]) -> (String, [String: Any])? {
        return nil
    }
}

