//
//  RouterWrapper+Navigate.swift
//  XiaoPengQiChe
//
//  Created by Kin on 2025/1/14.
//  Copyright © 2025 xiaopeng.com. All rights reserved.
//

import Foundation
import TheRouter
import bBox

public struct RouterHelperNaviationOption: OptionSet {
    public typealias RawValue = Int
    public var rawValue: Int
    public init(rawValue: Int) {
        self.rawValue = rawValue
    }

    public static let ignoreDocumentTitle = RouterHelperNaviationOption(rawValue: 1 << 0)
    public static let hideMoreButton = RouterHelperNaviationOption(rawValue: 1 << 1)
}

public typealias RouterHelperCompleteHandler = (String, Any?) -> Void

public extension RouterHelper {
    @discardableResult @objc static func canOpen(_ urlString: String) -> Bool {
        return TheRouter.canOpenURL(urlString) || (Self.shared.xpRouterUtilDelegate?.utilCanOpenURL(urlString) ?? false)
    }

    @available(*, deprecated, message: "全面切换到TheRouter之后不再支持模糊判断，请尽快处理")
    @discardableResult @objc static func canFuzzyOpen(_ urlString: String) -> Bool {
        if RouterCloudConfig.isNewRouterEnabled() {
            return TheRouter.canOpenURL(urlString) || (Self.shared.xpRouterUtilDelegate?.utilCanFuzzyOpenURL(urlString) ?? false)
        } else {
            return Self.shared.xpRouterUtilDelegate?.utilCanFuzzyOpenURL(urlString) ?? false
        }
    }

    @discardableResult @objc static func open(_ urlString: String) -> Bool {
        return open(urlString, userInfo: [String: Any](), title: nil, options: [])
    }

    @discardableResult @objc static func open(_ urlString: String, userInfo: [String: Any]) -> Bool {
        return open(urlString, userInfo: userInfo, title: nil, options: [])
    }

    @discardableResult @objc static func open(_ urlString: String, title: String) -> Bool {
        return open(urlString, userInfo: [String: Any](), title: title, options: [])
    }

    @discardableResult @objc static func open(_ urlString: String, userInfo: [String: Any], title: String) -> Bool {
        return open(urlString, userInfo: userInfo, title: title, options: [])
    }

    @discardableResult @objc static func openIgnoreTitle(_ urlString: String, userInfo: [String: Any], title: String) -> Bool {
        return open(urlString, userInfo: userInfo, title: title, options: [.ignoreDocumentTitle])
    }

    @discardableResult static func open(_ urlString: String, userInfo: [String: Any], title: String?, options: RouterHelperNaviationOption) -> Bool {
        var mergedUserInfo = userInfo
        if options.contains(.ignoreDocumentTitle) {
            mergedUserInfo["ignoreDocumentTitle"] = true
        }
        if options.contains(.hideMoreButton) {
            mergedUserInfo["hideMoreButton"] = true
        }
        if title != nil {
            mergedUserInfo["title"] = title
        }
        return Self.shared.realOpen(urlString, userInfo: userInfo, completion: nil)
    }

    private func realOpen(_ urlString: String, userInfo: [String: Any], completion: RouterHelperCompleteHandler?) -> Bool {
        if RouterCloudConfig.isNewRouterEnabled() {
            if useNewRouterOpen(urlString, userInfo: userInfo, completion: completion) {
                return true
            }
        }

        if xpRouterUtilDelegate?.utilOpenURL(urlString, userInfo: userInfo) == true {
            completion?(urlString, nil)
            return true
        }

        techTrack(status: -1, source: "N/A", msg: "URL \(urlString) cannot handle")
        BBLog.warning("Router \(urlString) cannot handle by XPRouter, force use TheRouter to handle")
        return useNewRouterOpen(urlString, userInfo: userInfo, completion: completion)
    }

    private func useNewRouterOpen(_ urlString: String, userInfo: [String: Any], completion: RouterHelperCompleteHandler?) -> Bool {
        if intercept(urlString, userInfo: userInfo) {
            completion?(urlString, nil)
            return true
        }

        let (newUrlString, newUserInfo) = customize(urlString, userInfo: userInfo)
        let (baseUrlString, extraUserInfo) = preprocess(urlString: newUrlString)
        var userInfo = newUserInfo
        userInfo.merge(dic: extraUserInfo)

        if TheRouter.openURL(baseUrlString, userInfo: userInfo) != nil {
            completion?(urlString, nil)
            techTrack(status: 0, source: "TheRouter", msg: "URL \(urlString) handled by TheRouter")
            return true
        }
        return false
    }

    private func intercept(_ urlString: String, userInfo: [String: Any]) -> Bool {
        for interceptor in interceptors {
            if interceptor.shouldIntercept(urlString, userInfo: userInfo) {
                techTrack(status: 0, source: "Interceptor", msg: "URL \(urlString) intercepted by \(interceptor.self)")
                return true
            }
        }
        return false
    }

    private func customize(_ urlString: String, userInfo: [String: Any]) -> (String, [String: Any]) {
        for customiser in customisers {
            if let newRouter = customiser.customise(urlString: urlString, userInfo: userInfo) {
                techTrack(status: 0, source: "Customiser", msg: "URL \(urlString) customised by \(customiser.self), new URL is \(newRouter.0)")
                return newRouter
            }
        }
        return (urlString, userInfo)
    }

    /// 预处理URL字符串，将URL和参数分离以兼容新旧两套逻辑
    ///
    /// - Parameter urlString: 需要处理的URL字符串
    /// - Returns 处理后的URL字符串和参数，参数可能为空
    private func preprocess(urlString: String) -> (String, [String: Any]) {
        var baseUrlString = urlString
        var extraParams = [String: Any]()

        if let url = URL(string: urlString) {
            baseUrlString = ""
            if let scheme = url.scheme {
                baseUrlString += scheme
            }
            baseUrlString += "://"
            if let host = url.host {
                baseUrlString += host
            }
            baseUrlString += url.path

            if let params = url.urlParameters {
                extraParams.merge(dic: params)
            }
        }

        return (baseUrlString, extraParams)
    }

    private func techTrack(status: Int, source: String, msg: String) {
        BBTracker.trackType(6, event: "B056", module: "P00004", label: [
            "scene": "RouterHelper",
            "source": source,
            "status": status,
            "error_message": msg
        ])
    }
}

