//
//  XPRouter.h
//  XiaoPengQiChe
//
//  Created by lijy on 2018/5/28.
//  Copyright © 2018年 xiaopeng.com. All rights reserved.
//  路由处理，绑定URL地址和对应的handler

#import <Foundation/Foundation.h>

#define XPRouterJointURL(urlPatter, params) [XPRouter jointURLPattern:urlPatter parameters:params]

extern NSString *const XPRouter_URL;
extern NSString *const XPRouter_UserInfo;
extern NSString *const XPRouter_Completion;

/**
 URL路由回调

 @param routerParameters 回调的参数，包含了XPRouter_URL、XPRouter_UserInfo、XPRouter_Completion、XPRouter_Block等信息
 */
typedef void (^XPRouterHandler)(NSDictionary *routerParameters);


/**
 某一次打开URL路由的 对应回调，该回调会在XPRouterHandler由业务开发者主动调用，否则，不会响应

 @param result 业务需要处理的参数
 */
typedef void (^XPCompletion)(id result);

@interface XPRouter : NSObject

+ (XPRouter *)instance;


#pragma mark -  register / unregister
/**
 注册URL路由，以及对应的处理handler，在handler 中可初始化UIViewController(或者UIView)，
 然后对UIViewController(或者UIView)做各种操作处理;  或者在handler 中做一些与界面无关的业务逻辑

 @param urlPattern 带scheme，如:xiaopeng://account/wallet/:replaceKeyWord
 @param handler 该block会带上回调的参数，包含了注册的URL对应参数(:replaceKeyWord)，以及打开URL的后边的参数。
                例如：xiaopeng://account/wallet/info?id={id}，
                info对应:replaceKeyWord，符号"?"的参数则按KV一一解析出来,如下：
                @{@"id": 4, @"replaceKeyWord" : @"info"}
 */
+ (void)registerURLPattern:(NSString *)urlPattern routerHandler:(XPRouterHandler)handler;


/**
 取消注册某个URL路由

 @param urlPattern 带scheme，如:xiaopeng://account/wallet/:replaceKeyWord
 */
+ (void)unregisterURLPattern:(NSString *)urlPattern;

#pragma mark - open URL
/**
 打开URL, 在注册的 URL->handler 中寻找，如果找到，则执行handler

 @param url 带scheme，xiaopeng://account/wallet/info?id={id}
 */
+ (void)openURL:(NSString *)url;

/**
 打开URL，同时带上回调

 @param url 带scheme，xiaopeng://account/wallet/info?id={id}
 @param completion url 处理完成后的回调，具体调用由对应的XPRouterHandler中触发
 */
+ (void)openURL:(NSString *)url completion:(XPCompletion)completion;

/**
 打开URL，同时带上额外的信息(用于传递无法通过URL地址传递到对象，比如：UIImage等参数)，和回调

 @param url 带scheme，xiaopeng://account/wallet/info?id={id}
 @param extraUserInfo 额外的信息(用于传递无法通过URL地址传递到对象，比如：UIImage等参数)
 @param completion URL 处理完成后的回调，具体调用由对应的XPRouterHandler中触发
 */
+ (BOOL)openURL:(NSString *)url extraUserInfo:(NSDictionary *)extraUserInfo completion:(XPCompletion)completion;


/**
 是否能打开URL，模糊匹配, 即xiaopeng://account/wallet/info、xiaopeng://account/wallet或 xiaopeng://account、xiaopeng；均认为可打开
 在注册的 URL路由 中寻找，如果找到，则返回YES
 注意：http或https不会做判断，只判断注册的路由

 @param url 带scheme，xiaopeng://account/wallet/info?id={id}
 @return BOOL， YES:能打开，NO，不能打开
 */
+ (BOOL)canFuzzyMatchOpenURL:(NSString *)url;

/**
 是否能打开URL，注意：设置是否模糊匹配还是完全匹配
 在注册的 URL路由 中寻找，如果找到，则返回YES
 注意：http或https不会做判断，只判断注册的路由

 @param url  带scheme，xiaopeng://account/wallet/info?id={id}
 @param exactly 是否完全匹配路径，NO：不完全匹配路径，xiaopeng://account/wallet/info、xiaopeng://account/wallet或 xiaopeng://account、xiaopeng；
                               YES：完全匹配路径, 匹配到xiaopeng://account/wallet/info
 @return BOOL， YES:能打开，NO，不能打开
 */
+ (BOOL)canOpenURL:(NSString *)url matchExactly:(BOOL)exactly;


#pragma mark - joint URL
/**
 调用此方法来拼接URL，即使用parameters参数去替换pattern中的对应数据

 @param pattern 带scheme，xiaopeng://account/wallet/:replaceKeyWord
 @param parameters 数组，数量要和pattern中被替换的变量数一致，例如：@[@"info"]
 @return 拼接好的URL,如： xiaopeng://account/wallet/info
 */
+ (NSString *)jointURLPattern:(NSString *)pattern parameters:(NSArray *)parameters;


@end

