//
//  RouterSystemConfig.swift
//  XPBase_Router
//
//  Created by Kin on 2025/11/25.
//

import Foundation
import XPConfigCenter
import bBox

private let APP_ROUTER_WHITE_LIST = "APP_ROUTER_WHITE_LIST"

@objc(XPRouterSystemConfig) public class RouterSystemConfig: NSObject {
    @objc public static let shared = RouterSystemConfig()
    private let rwlock = RWLock([String](), label: "RouterWhitelist")

    @objc public var routerWhitelist: [String] {
        get {
            if rwlock.snapshot.isEmpty {
                if let config = parseAndSave() {
                    return config
                } else {
                    requestConfig()
                }
            }            
            return rwlock.snapshot
        }
    }

    private func requestConfig() {
        XPConfigCenter.config(forKeys: [APP_ROUTER_WHITE_LIST], ignoreCache: true) { config, error in
            self.parseAndSave()
        }
    }

    private func parseAndSave() -> [String]? {
        if let response = XPConfigCenter.config(forKeys: [APP_ROUTER_WHITE_LIST]),
           let responseArray = response[APP_ROUTER_WHITE_LIST] as? [Any],
           let responseString = responseArray.first as? String,
           let responseData = responseString.data(using: .utf8),
           let whitelistObj = try? JSONSerialization.jsonObject(with: responseData) as? [String: Any],
           let whitelist = whitelistObj["whiteList"] as? [String] {
            rwlock.asyncWrite(whitelist)
            return whitelist
        } else {
            return nil
        }
    }
}

