import UIKit
import CloudConfig

@objc public class RouterCloudConfig: NSObject {
    private static var newRouterEnable: Bool?
    private static var newServiceEnable: Bool?

    @objc public static func isNewRouterEnabled() -> Bool {
        if let newRouterEnable = Self.newRouterEnable {
            return newRouterEnable
        } else {
            let obj = CloudConfig.config(forKeyPath: "TheRouter.migration.newRouter")
            if obj is Bool {
                newRouterEnable = obj as! Bool
                return obj as! Bool
            } else {
                newRouterEnable = false
                return false
            }
        }
    }

    @objc public static func isNewServiceEnabled() -> Bool {
        if let newServiceEnable = Self.newServiceEnable {
            return newServiceEnable
        } else {
            let obj = CloudConfig.config(forKeyPath: "TheRouter.migration.newService")
            if obj is Bool {
                newServiceEnable = obj as! Bool
                return obj as! Bool
            } else {
                newServiceEnable = false
                return false
            }
        }
    }
}

