import Foundation
import XPNetwork
import bBox

// MARK: - XPIMInputPredicateServiceDelegate

/// 输入建议服务回调协议
protocol XPIMInputPredicateServiceDelegate: AnyObject {
    /// 建议数据返回
    func inputPredicateService(_ service: XPIMInputPredicateService, 
                               didReceiveSuggestions suggestions: [XPIMInputSuggestionItem])

    /// 建议请求失败
    func inputPredicateService(_ service: XPIMInputPredicateService, 
                               didFailWithError error: Error)
}

// MARK: - XPIMInputPredicateService

/// 输入建议服务类
class XPIMInputPredicateService {
    // MARK: - Properties

    /// 代理
    weak var delegate: XPIMInputPredicateServiceDelegate?

    /// 建议数量
    var suggestionCount: Int = 3

    /// 当前请求ID
    private var currentRequestId: String?

    // MARK: - Initialization

    init() {}

    // MARK: - Public Methods

    /// 处理文本变化
    /// - Parameter text: 当前输入文本
    func handleTextChange(_ text: String) {
        // 处理空输入和纯空白字符输入（不触发API调用）
        let trimmedText = text.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmedText.isEmpty else {
            // 空输入，不触发API调用
            return
        }

        // 生成唯一的requestId
        let requestId = UUID().uuidString
        currentRequestId = requestId

        // 调用API获取建议
        Task {
            do {
                let st = CACurrentMediaTime()
                let data = try await fetchSuggestions(
                    searchWord: text,
                    requestId: requestId,
                    num: suggestionCount
                )

                BBLog.i(tag: "IM", "API response time: \(CACurrentMediaTime() - st) seconds")

                // 检查请求是否仍然有效
                guard currentRequestId == requestId else {
                    BBLog.i(tag: "IM", "Request \(requestId) is outdated, discarding response")
                    return
                }

                // 处理响应
                BBLog.i(
                    tag: "IM",
                    "Received \(data.suggestions.count) suggestions"
                )
                await MainActor.run {
                    delegate?.inputPredicateService(self, didReceiveSuggestions: data.suggestions)
                }
            } catch {
                BBLog.e(tag: "IM", "Failed to fetch suggestions: \(error)")
                await MainActor.run {
                    delegate?.inputPredicateService(self, didFailWithError: error)
                }
            }
        }
    }

    /// 取消所有待处理的请求
    func cancelAllRequests() {
        currentRequestId = nil
    }

    // MARK: - Private Methods

    /// 获取建议
    /// - Parameters:
    ///   - searchWord: 搜索词（用户输入文本）
    ///   - requestId: 请求ID（唯一标识符）
    ///   - num: 建议数量
    /// - Returns: API响应
    private func fetchSuggestions(searchWord: String, requestId: String, num: Int) async throws -> XPIMInputSuggestionData {
        return try await withCheckedThrowingContinuation { continuation in
            let params: [String: Any] = [
                "searchWord": searchWord,
                "requestId": requestId,
                "num": num
            ]

//            continuation.resume(returning: XPIMInputSuggestionData(suggestions: [
//                XPIMInputSuggestionItem(text: "如何快速充电", highlight: "如何快速<strong>充电</strong>")
//            ]))
//            return

            XPAPI.request
                .path("/xp-cs-app-biz-boot/app/algo/suggest/question")
                .method(.POST)
                .payload(params)
                .subscribe { response in
                    // 检查响应是否成功
                    if response.isSuccess,
                       let json = response.data as? [String: Any],
                       let data = try? JSONSerialization.data(withJSONObject: json, options: []) {
                        // 尝试解析JSON
                        do {
                            let suggestionResponse = try JSONDecoder().decode(XPIMInputSuggestionData.self, from: data)
                            continuation.resume(returning: suggestionResponse)
                        } catch {
                            BBLog.e(tag: "IM", "Failed to parse response: \(error)")
                            continuation.resume(throwing: XPIMInputError.parseError)
                        }
                    } else {
                        let errorMsg = response.message ?? "Unknown error"
                        BBLog.e(tag: "IM", "API request failed: \(errorMsg)")
                        continuation.resume(throwing: XPIMInputError.apiError(errorMsg))
                    }
                }
        }
    }
}

