    }

    // MARK: - Setup

    private func setupUI() {
        // 设置视图样式
        backgroundColor = .xp_background
        layer.cornerRadius = 12
        layer.maskedCorners = [.layerMinXMinYCorner, .layerMaxXMinYCorner]

        // 添加子视图
        addSubview(headerLabel)
        addSubview(closeButton)
        addSubview(stackView)

        // 设置关闭按钮事件
        closeButton.addTarget(self, action: #selector(closeButtonTapped), for: .touchUpInside)

        // 设置约束
        setupConstraints()
    }

    private func setupConstraints() {
        // 使用SnapKit设置约束

        // 头部标签约束
        headerLabel.snp.makeConstraints { make in
            make.top.equalToSuperview().offset(12)
            make.leading.equalToSuperview().offset(16)
            make.trailing.equalTo(closeButton.snp.leading).offset(-8)
            make.height.equalTo(22)
        }

        // 关闭按钮约束（右上角）
        closeButton.snp.makeConstraints { make in
            make.centerY.equalTo(headerLabel)
            make.trailing.equalToSuperview().offset(-15)
            make.width.height.equalTo(24)
        }

        // StackView约束
        stackView.snp.makeConstraints { make in
            make.top.equalTo(headerLabel.snp.bottom).offset(2)
            make.leading.trailing.equalToSuperview()
            make.bottom.equalToSuperview().offset(-8)
        }
    }

    // 重写intrinsicContentSize，让视图根据内容自动调整高度
    override var intrinsicContentSize: CGSize {
        // 强制布局以获取准确的contentSize
        layoutIfNeeded()

        // 头部高度：12(top) + 22(label) = 34
        let headerHeight: CGFloat = 34
        // 底部内边距：10
        let bottomPadding: CGFloat = 6
        // StackView的实际高度
        let stackViewHeight = stackView.systemLayoutSizeFitting(UIView.layoutFittingCompressedSize).height

        // 总高度 = 头部 + StackView内容 + 底部内边距
        let totalHeight = headerHeight + stackViewHeight + bottomPadding

        // 返回不超过最大高度的实际高度
        return CGSize(width: UIView.noIntrinsicMetric, height: min(totalHeight, maxHeight))
    }

    // MARK: - Actions

    @objc private func closeButtonTapped() {
        delegate?.suggestionListViewDidRequestClose(self)
    }

    // MARK: - Public Methods

    /// 更新建议数据
    /// - Parameter suggestions: 新的建议数组
    func updateSuggestions(_ suggestions: [XPIMInputSuggestionItem]) {
        self.suggestions = suggestions
    }

    /// 更新StackView内容
    private func updateStackView() {
        // 清空现有视图
        stackView.arrangedSubviews.forEach { $0.removeFromSuperview() }

        // 为每个建议创建一个视图
        for (index, suggestion) in suggestions.enumerated() {
            let itemView = createSuggestionItemView(for: suggestion, at: index)
            stackView.addArrangedSubview(itemView)
        }

        // 通知系统重新计算intrinsicContentSize
        invalidateIntrinsicContentSize()
    }

    /// 创建建议项视图
    /// - Parameters:
    ///   - suggestion: 建议数据
    ///   - index: 索引
    /// - Returns: 建议项视图
    private func createSuggestionItemView(for suggestion: XPIMInputSuggestionItem, at index: Int) -> UIView {
        let containerView = UIView()
        containerView.backgroundColor = .clear

        // 创建标签
        let label = UILabel()
        label.numberOfLines = 1
        label.font = .xp.font(name: .pingFangSCRegular, size: 14)

        // 渲染高亮文本
        let attributedText = renderHighlightedText(text: suggestion.text, highlight: suggestion.highlight)
        label.attributedText = attributedText

        containerView.addSubview(label)

        // 设置约束
        label.snp.makeConstraints { make in
            make.top.equalToSuperview().offset(8)
            make.leading.equalToSuperview().offset(16)
            make.trailing.equalToSuperview().offset(-16)
            make.bottom.equalToSuperview()
            make.height.greaterThanOrEqualTo(22)
        }

        // 添加点击手势
        let tapGesture = UITapGestureRecognizer(target: self, action: #selector(handleItemTap(_:)))
        containerView.addGestureRecognizer(tapGesture)
        containerView.tag = index

        return containerView
    }

    /// 处理建议项点击
    @objc private func handleItemTap(_ gesture: UITapGestureRecognizer) {
        guard let view = gesture.view else { return }
        let index = view.tag

        guard index >= 0 && index < suggestions.count else { return }
        let suggestion = suggestions[index]

        delegate?.suggestionListView(self, didSelectSuggestion: suggestion)
    }

    // MARK: - Touch Event Handling

    // 重写触摸事件方法，阻止事件传递到NIMSessionViewController
    // 这样点击建议列表任何位置都不会隐藏键盘
    override func touchesBegan(_ touches: Set<UITouch>, with event: UIEvent?) {
        // 不调用super.touchesBegan，阻止事件传递
    }

    override func touchesMoved(_ touches: Set<UITouch>, with event: UIEvent?) {
        // 不调用super，阻止事件传递
    }

    override func touchesEnded(_ touches: Set<UITouch>, with event: UIEvent?) {
        // 不调用super，阻止事件传递
    }

    override func touchesCancelled(_ touches: Set<UITouch>, with event: UIEvent?) {
        // 不调用super，阻止事件传递
    }

    /// 渲染高亮文本
    /// - Parameters:
    ///   - text: 原始文本
    ///   - highlight: 包含<strong>标签的HTML文本
    /// - Returns: 渲染后的NSAttributedString
    private func renderHighlightedText(text: String, highlight: String) -> NSAttributedString {
        // 从highlight中提取<strong></strong>包裹的文本
        let highlightTexts = extractHighlightTexts(from: highlight)

        // 创建富文本
        let attributedString = NSMutableAttributedString(string: text)

        // 设置基础样式
        let baseAttributes: [NSAttributedString.Key: Any] = [
            .font: UIFont.xp.font(name: .pingFangSCRegular, size: 14),
            .foregroundColor: UIColor.xp_primaryText
        ]
        attributedString.addAttributes(baseAttributes, range: NSRange(location: 0, length: text.count))

        // 高亮样式
        let highlightAttributes: [NSAttributedString.Key: Any] = [
            .font: UIFont.xp.font(name: .pingFangSCRegular, size: 14),
            .foregroundColor: UIColor.xp_commonBrandText
        ]

        // 在text中查找并高亮这些文本
        for highlightText in highlightTexts {
            var searchRange = NSRange(location: 0, length: text.count)

            while searchRange.location < text.count {
                let range = (text as NSString).range(of: highlightText, options: [], range: searchRange)

                if range.location == NSNotFound {
                    break
                }

                // 应用高亮样式
                attributedString.addAttributes(highlightAttributes, range: range)

                // 更新搜索范围，继续查找下一个匹配
                searchRange.location = range.location + range.length
                searchRange.length = text.count - searchRange.location
            }
        }

        return attributedString
    }

    /// 从HTML文本中提取<strong>标签包裹的文本
    /// - Parameter htmlText: 包含<strong>标签的HTML文本
    /// - Returns: 提取出的高亮文本数组
    private func extractHighlightTexts(from htmlText: String) -> [String] {
        var highlightTexts: [String] = []

        // 使用正则表达式提取<strong>标签内的文本
        let pattern = "<strong>(.*?)</strong>"

        do {
            let regex = try NSRegularExpression(pattern: pattern, options: [])
            let matches = regex.matches(in: htmlText, options: [], range: NSRange(location: 0, length: htmlText.count))

            for match in matches {
                if match.numberOfRanges > 1 {
                    let range = match.range(at: 1)
                    if let swiftRange = Range(range, in: htmlText) {
                        let highlightText = String(htmlText[swiftRange])
                        highlightTexts.append(highlightText)
                    }
                }
            }
        } catch {
            BBLog.e(tag: "IM", "Regex extraction failed: \(error.localizedDescription)")
        }

        return highlightTexts
    }
}

