import Foundation
import UIKit
import bBox
import SnapKit

// MARK: - Associated Object Keys

private var inputPredicateServiceKey: UInt8 = 0
private var suggestionListViewKey: UInt8 = 0
private var tapGestureRecognizerKey: UInt8 = 0

// MARK: - NIMSessionViewController Extension

extension NIMSessionViewController {

    // MARK: - Properties

    /// 输入建议服务
    private var inputPredicateService: XPIMInputPredicateService? {
        get {
            return objc_getAssociatedObject(self, &inputPredicateServiceKey) as? XPIMInputPredicateService
        }
        set {
            objc_setAssociatedObject(self, &inputPredicateServiceKey, newValue, .OBJC_ASSOCIATION_RETAIN_NONATOMIC)
        }
    }

    /// 建议列表视图
    private var suggestionListView: XPIMInputSuggestionListView? {
        get {
            return objc_getAssociatedObject(self, &suggestionListViewKey) as? XPIMInputSuggestionListView
        }
        set {
            objc_setAssociatedObject(self, &suggestionListViewKey, newValue, .OBJC_ASSOCIATION_RETAIN_NONATOMIC)
        }
    }

    /// 外部点击手势识别器
    private var tapGestureRecognizer: UITapGestureRecognizer? {
        get {
            return objc_getAssociatedObject(self, &tapGestureRecognizerKey) as? UITapGestureRecognizer
        }
        set {
            objc_setAssociatedObject(self, &tapGestureRecognizerKey, newValue, .OBJC_ASSOCIATION_RETAIN_NONATOMIC)
        }
    }

    // MARK: - Setup

    /// 设置输入建议功能
    @objc public func setupInputSuggestion() {
        guard suggestionListView == nil else { return }
        // 创建并配置XPIMInputPredicateService实例
        let service = XPIMInputPredicateService()
        service.delegate = self
        self.inputPredicateService = service

        // 创建并配置XPIMInputSuggestionListView实例
        let listView = XPIMInputSuggestionListView(frame: .zero)
        listView.delegate = self
        listView.isHidden = true // 初始隐藏
        self.suggestionListView = listView

        // 添加建议列表视图到视图层级
        view.addSubview(listView)

        // 设置建议列表视图的布局约束（位于quotedView上方）
        setupSuggestionListConstraints()

        // 设置键盘通知监听
        setupKeyboardNotifications()
    }

    /// 设置建议列表视图的约束
    private func setupSuggestionListConstraints() {
        guard let listView = suggestionListView else { return }

        // 使用SnapKit设置约束
        listView.snp.makeConstraints { make in
            make.leading.equalToSuperview()
            make.trailing.equalToSuperview()
            make.bottom.equalTo(sessionInputView.toolBar.quotedView.snp.top)
            // 设置最大高度，让内容自动撑开但不超过最大值
            make.height.lessThanOrEqualTo(listView.maxHeight)
        }
    }

    /// 设置键盘通知监听
    private func setupKeyboardNotifications() {
        // 监听键盘隐藏通知
        NotificationCenter.default.addObserver(
            self,
            selector: #selector(keyboardWillHide(_:)),
            name: UIResponder.keyboardWillHideNotification,
            object: nil
        )
    }

    // MARK: - Actions

    /// 处理键盘隐藏事件
    @objc private func keyboardWillHide(_ notification: Notification) {
        // 当键盘收起时，隐藏建议列表（不触发埋点）
        guard let listView = suggestionListView, !listView.isHidden else {
            return
        }

        // 直接隐藏，不触发关闭按钮的埋点
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.1) { [weak self] in
            self?.hideSuggestionList()
        }
    }

    // MARK: - UI Management

    /// 显示建议列表
    func showSuggestionList(with suggestions: [XPIMInputSuggestionItem]) {
        guard let listView = suggestionListView else { return }

        // 更新建议数据（会自动触发updateStackView）
        listView.updateSuggestions(suggestions)

        // 显示视图（带淡入动画）
//        listView.alpha = 0
        listView.isHidden = false

        // 埋点：鹏管家输入入联想内容曝光
        XPIMEvents.sendEvent(module: .sessionList, event: .inputSuggestionExposure)

//        UIView.animate(withDuration: 0.2) {
//            listView.alpha = 1.0
//            self.view.layoutIfNeeded()
//        }
    }

    /// 隐藏建议列表
    @objc public func hideSuggestionList() {
        // 取消所有待处理的请求
        inputPredicateService?.cancelAllRequests()

        guard let listView = suggestionListView, !listView.isHidden else {
            return
        }

        // 隐藏视图（带淡出动画）
//        UIView.animate(withDuration: 0.2, animations: {
//            listView.alpha = 0
//        }) { _ in
            listView.isHidden = true
            listView.updateSuggestions([]) // 清空建议数据
//        }
    }

    /// 处理建议选择
    func handleSuggestionSelection(_ suggestion: XPIMInputSuggestionItem) {
        // 埋点：鹏管家输入入联想内容点击
        XPIMEvents.sendEvent(module: .sessionList, event: .inputSuggestionClick)

        // 提取建议的text字段
        let text = suggestion.text

        // 更新NIMInputView的文本内容
        if let toolBar = sessionInputView.toolBar {
            let range = NSRange(location: 0, length: toolBar.contentText?.length ?? 0)
            toolBar.deleteText(range)
            toolBar.insertText(text)
        }

        // 隐藏建议列表
        hideSuggestionList()

        // 设置输入焦点到NIMInputView
        sessionInputView.toolBar.showsKeyboard = true
    }

    /// 处理文本变化（供Objective-C调用）
    @objc public func handleInputTextChange(_ text: String) {

        // 确保 suggestionListView 已初始化
        setupInputSuggestion()

        // 在文本变化时隐藏当前显示的建议列表
        if let listView = suggestionListView,
           !listView.isHidden,
           text.isEmpty {
            hideSuggestionList()
        }

        // 调用服务处理文本变化
        inputPredicateService?.handleTextChange(text)
    }

    // MARK: - Lifecycle

    /// 清理输入建议功能
    @objc public func cleanupInputSuggestion() {
        // 取消所有待处理的请求
        inputPredicateService?.cancelAllRequests()

        // 移除手势识别器
        if let tapGesture = tapGestureRecognizer {
            view.removeGestureRecognizer(tapGesture)
        }

        // 移除键盘通知监听
        NotificationCenter.default.removeObserver(
            self,
            name: UIResponder.keyboardWillHideNotification,
            object: nil
        )

        // 移除建议列表视图
        suggestionListView?.removeFromSuperview()
    }
}

// MARK: - XPIMInputPredicateServiceDelegate

extension NIMSessionViewController: XPIMInputPredicateServiceDelegate {

    /// 建议数据返回
    func inputPredicateService(_ service: XPIMInputPredicateService, 
                               didReceiveSuggestions suggestions: [XPIMInputSuggestionItem]) {
        // 检查code是否为200（已在服务层处理）
        // 显示建议列表
        if suggestions.isEmpty {
            hideSuggestionList()
        } else {
            showSuggestionList(with: suggestions)
        }
    }

    /// 建议请求失败
    func inputPredicateService(_ service: XPIMInputPredicateService, 
                               didFailWithError error: Error) {
        // 记录错误日志但不影响UI
        BBLog.e(tag: "IM", "Failed to fetch suggestions: \(error)")

        // 隐藏建议列表
        hideSuggestionList()
    }
}

// MARK: - XPIMInputSuggestionListViewDelegate

extension NIMSessionViewController: XPIMInputSuggestionListViewDelegate {

    /// 用户选择了建议
    func suggestionListView(_ view: XPIMInputSuggestionListView, 
                           didSelectSuggestion suggestion: XPIMInputSuggestionItem) {
        handleSuggestionSelection(suggestion)
    }

    /// 用户请求关闭列表
    func suggestionListViewDidRequestClose(_ view: XPIMInputSuggestionListView) {
        // 埋点：鹏管家输入入联想内容关闭按钮点击
        XPIMEvents.sendEvent(module: .sessionList, event: .inputSuggestionCloseClick)

        hideSuggestionList()
    }
}
